class Solution:
    def latestTimeCatchTheBus(self, buses: List[int], passengers: List[int], capacity: int) -> int:
        buses.sort()
        passengers.sort()
        i = 0
        for bus in buses:
            while i < len(passengers) and passengers[i] <= bus:
                i += 1
            if i < len(passengers):
                return min(bus, passengers[i - 1] + capacity)
        return buses[-1]
